-- 027_fixed_splits.sql
-- Retire the slot-filling generator and serve pre-built splits verbatim.
--
-- The picker (split_definitions -> split_days -> split_day_slots + the
-- tier/role ranking in split-fill.ts) is replaced by 10 fixed splits taken
-- straight from the elmadhi fixed-splits sheet: one per (gender, days_per_week),
-- each day holding 7 fixed exercises with the sheet's own reps, swap options and
-- coaching advice. Program generation is now "match gender + days, copy the
-- rows" — no ranking, filtering, or candidate pool.
--
-- Exercises are resolved to the existing canonical catalog by name so live
-- sessions, set logging, progress charts and illustrations keep working. Six
-- sheet names use a slightly different spelling than the catalog and are
-- aliased in the seed below.
--
-- The questionnaire is slimmed to what actually matches or adapts a split:
-- gender + days_per_week select it, experience + recovery guide the day count,
-- and location/equipment/injuries power the manual swap picker. Every question
-- that only fed the retired picker (session_duration, training_style,
-- pullup_ability, lift_comfort, age_bracket, body_focus, exercise_dislikes,
-- weight_goal, cardio_preference) is removed.
--
-- The old split_definitions / split_days / split_day_slots tables are left in
-- place but unused; nothing reads them after this migration.
--
-- Paste into Supabase Dashboard -> SQL Editor -> Run.

BEGIN;

-- ============================================================
-- 1. Fixed-split tables
-- ============================================================
CREATE TABLE IF NOT EXISTS fixed_splits (
  id            TEXT PRIMARY KEY,
  gender        TEXT NOT NULL CHECK (gender IN ('Male', 'Female')),
  days_per_week INT  NOT NULL CHECK (days_per_week BETWEEN 2 AND 6),
  title_en      TEXT NOT NULL,
  week_order_en TEXT,
  UNIQUE (gender, days_per_week)
);

CREATE TABLE IF NOT EXISTS fixed_split_days (
  id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  fixed_split_id TEXT NOT NULL REFERENCES fixed_splits(id) ON DELETE CASCADE,
  day_number     INT  NOT NULL,
  day_name_en    TEXT NOT NULL,
  day_name_ar    TEXT,
  description_en TEXT,
  UNIQUE (fixed_split_id, day_number)
);

CREATE TABLE IF NOT EXISTS fixed_split_exercises (
  id                 UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  fixed_split_day_id UUID NOT NULL REFERENCES fixed_split_days(id) ON DELETE CASCADE,
  order_index        INT  NOT NULL,
  exercise_id        UUID NOT NULL REFERENCES exercises(id),
  reps               TEXT NOT NULL,
  swap_options       JSONB NOT NULL DEFAULT '[]'::jsonb,
  advice_en          TEXT,
  UNIQUE (fixed_split_day_id, order_index)
);

-- Read-only reference data, mirroring split_definitions' policy.
ALTER TABLE fixed_splits ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS fixed_splits_read ON fixed_splits;
CREATE POLICY fixed_splits_read ON fixed_splits FOR SELECT USING (TRUE);

ALTER TABLE fixed_split_days ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS fixed_split_days_read ON fixed_split_days;
CREATE POLICY fixed_split_days_read ON fixed_split_days FOR SELECT USING (TRUE);

ALTER TABLE fixed_split_exercises ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS fixed_split_exercises_read ON fixed_split_exercises;
CREATE POLICY fixed_split_exercises_read ON fixed_split_exercises FOR SELECT USING (TRUE);

-- ============================================================
-- Seed: 10 fixed splits (male + female, 2..6 days), verbatim from
-- elmadhi_fixed_workout_splits_final_database. Each day holds 7 fixed
-- exercises resolved to the canonical catalog by name (6 aliases).
-- ============================================================

DELETE FROM fixed_split_exercises;
DELETE FROM fixed_split_days;
DELETE FROM fixed_splits;




-- ============================================================
-- 3. Guard: every fixed exercise resolved to a catalog row.
--    A mis-spelled name would silently insert NULL exercise_id; the NOT NULL
--    column already blocks that, but assert the full count too.
-- ============================================================
DO $$
DECLARE
  n INT;
BEGIN
  SELECT COUNT(*) INTO n FROM fixed_split_exercises;
  IF n <> 280 THEN
    RAISE EXCEPTION 'fixed_split_exercises seeded % rows, expected 280', n;
  END IF;
END $$;

-- ============================================================
-- 4. Slim the questionnaire to what matches or adapts a fixed split.
--    gender + days_per_week select the split; experience + recovery guide the
--    day count; location/equipment/injuries power the manual swap picker.
-- ============================================================
DELETE FROM questionnaire_questions;

COMMIT;

