  ((SELECT id FROM fixed_split_days WHERE fixed_split_id='full_body_2day_male' AND day_number=1), 1, (SELECT id FROM exercises WHERE name_en='Back Squat'), '6-10', '["Hack Squat", "Smith Machine Squat", "Goblet Squat", "Front Squat", "Bodyweight Squat", "Leg Press", "Single-Leg Leg Press", "Horizontal Leg Press"]'::jsonb, 'Brace your core before each rep. | Keep knees tracking with toes. | Control depth and stand up strong.'),
