  ((SELECT id FROM fixed_split_days WHERE fixed_split_id='full_body_2day_male' AND day_number=1), 3, (SELECT id FROM exercises WHERE name_en='Lat Pulldown'), '6-10', '["Close-Grip Lat Pulldown", "Assisted Pull-Up", "Pull-Up"]'::jsonb, 'Pull elbows down toward your ribs. | Keep chest up and shoulders away from ears. | Control the stretch at the top.'),
  ((SELECT id FROM fixed_split_days WHERE fixed_split_id='full_body_2day_male' AND day_number=1), 4, (SELECT id FROM exercises WHERE name_en='Machine Row'), '6-10', '["T-Bar Row", "Bent-Over Barbell Row", "Band Row"]'::jsonb, 'Keep your spine neutral. | Pull elbows back with control. | Avoid using lower-back momentum.'),
  ((SELECT id FROM fixed_split_days WHERE fixed_split_id='full_body_2day_male' AND day_number=1), 5, (SELECT id FROM exercises WHERE name_en='Pec Deck'), '10-15', '["Cable Crossover", "Incline Cable Fly", "Dumbbell Fly", "Band Chest Fly"]'::jsonb, 'Keep shoulders down and chest open. | Use control and avoid swinging. | Stop the set when you stop feeling the chest.'),
  ((SELECT id FROM fixed_split_days WHERE fixed_split_id='full_body_2day_male' AND day_number=1), 6, (SELECT id FROM exercises WHERE name_en='Incline Dumbbell Press'), '6-10', '["Incline Machine Press", "Smith Machine Incline Press", "Incline Barbell Press", "Incline Push-Up"]'::jsonb, 'Keep shoulder blades stable on the bench. | Lower the weight with control toward upper chest. | Push strongly without bouncing.'),
