  ('goal', 0, 'What''s your main goal?', 'ما هو هدفك الأساسي؟', 'single_select', '["Muscle growth (hypertrophy)","Strength","Fat loss","Body recomposition (lose fat + build muscle)","General fitness / home convenience"]'::jsonb, '["بناء العضلات (تضخيم)","زيادة القوة","خسارة الدهون","إعادة تشكيل الجسم (خسارة دهون + بناء عضل)","لياقة عامة / راحة منزلية"]'::jsonb, NULL, NULL),
  ('gender', 1, 'What''s your biological sex? We use it to match you to the right split.', 'ما هو جنسك البيولوجي؟ نستعمله لاختيار التقسيمة المناسبة ليك.', 'single_select', '["Male","Female","Prefer not to say"]'::jsonb, '["ذكر","أنثى","نفضّل ما نقولش"]'::jsonb, NULL, NULL),
  ('experience', 2, 'How long have you been training consistently?', 'منذ متى وأنت تتدرب بانتظام؟', 'single_select', '["Beginner (0-6 months)","Intermediate (6mo-2yrs)","Advanced (2+ yrs)"]'::jsonb, '["مبتدئ (0-6 أشهر)","متوسط (6 أشهر - سنتين)","متقدم (أكثر من سنتين)"]'::jsonb, NULL, NULL),
  ('recovery_capacity', 3, 'How would you describe your sleep and stress levels lately?', 'كيفاش تلقى نومك ومستوى التوتر متاعك في الفترة الأخيرة؟', 'single_select', '["Good sleep, low stress","Okay — some off days","Poor sleep or high stress lately"]'::jsonb, '["نوم جيد وتوتر منخفض","لا بأس — بعض الأيام الصعبة","نوم سيء أو توتر مرتفع مؤخراً"]'::jsonb, NULL, NULL),
  ('days_per_week', 4, 'How many days per week can you train? If you''re a beginner or your recovery is low, 2-3 days is plenty.', 'قداش من نهار في الجمعة تنجم تتمرن؟ إذا كنت مبتدئ ولا التعافي متاعك ضعيف، 2-3 أيام يكفيو برشا.', 'single_select', '["2","3","4","5","6"]'::jsonb, '["2","3","4","5","6"]'::jsonb, NULL, NULL),
  ('location', 5, 'Where will you train?', 'وين باش تتمرن؟', 'single_select', '["Gym only","Home only","Home + Gym (hybrid)"]'::jsonb, '["نادي رياضي فقط","الدار فقط","دار + نادي (مختلط)"]'::jsonb, NULL, NULL),
  ('equipment_gym', 6, 'At the gym, what do you have access to?', 'في النادي، شنوّة المعدات المتوفرة ليك؟', 'multi_select', '["Barbell","Dumbbells","Cable machines","Selectorized machines","Kettlebell"]'::jsonb, '["بار حديد","دمبل","أجهزة كابل","أجهزة مقعدة (سيليكتورايز)","كيتل بيل"]'::jsonb, '{"location":["Gym only","Home + Gym (hybrid)"]}'::jsonb, NULL),
  ('equipment_home', 7, 'At home, what do you have access to?', 'في الدار، شنوّة المعدات المتوفرة ليك؟', 'multi_select', '["Dumbbells","Resistance bands","Pull-up bar","Kettlebell","Bodyweight only"]'::jsonb, '["دمبل","مطاط مقاومة","عارضة عقلة","كيتل بيل","وزن الجسم فقط"]'::jsonb, '{"location":["Home only","Home + Gym (hybrid)"]}'::jsonb, NULL),
  ('injuries', 8, 'Any current or recurring injuries? (select all that apply)', 'عندك أي إصابات حالية ولا متكررة؟ (اختر كل ما ينطبق)', 'multi_select', '["None","Lower back","Knee","Shoulder","Wrist / elbow","Neck"]'::jsonb, '["لا شيء","أسفل الظهر","الركبة","الكتف","الرسغ / المرفق","الرقبة"]'::jsonb, NULL, NULL),
  ('pregnancy_status', 9, 'Does any of this apply to you? (Consult your doctor before starting any program)', 'ينطبق عليك أي مما يلي؟ (استشيري الطبيب قبل ما تبداي أي برنامج)', 'single_select', '["None","Pregnant","Postpartum (0-6 months)","Postpartum (6+ months)"]'::jsonb, '["لا شيء","حامل","بعد الولادة (0-6 أشهر)","بعد الولادة (أكثر من 6 أشهر)"]'::jsonb, '{"gender":["Female"]}'::jsonb, NULL);
